package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testGetEscapeCharacter() throws NoSuchFieldException, IllegalAccessException {
        // Create a CSVFormat instance
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Mock the private field escapeCharacter
        Character escapeCharacter = '$';
        Field field = CSVFormat.class.getDeclaredField("escapeCharacter");
        field.setAccessible(true);
        field.set(csvFormat, escapeCharacter);

        // Call the getEscapeCharacter method using reflection
        Character result = csvFormat.getEscapeCharacter();

        // Verify the result
        assertEquals(escapeCharacter, result);
    }
}
